CREATE OR REPLACE FUNCTION fp_get_bank_div (as_memno text) RETURNS varchar AS $body$
DECLARE

ls_bank_div sc_mem_m_member_bank_accno.bank_acc_no%type;

BEGIN

select min( bank_acc_no  ) into STRICT ls_bank_div
from sc_mem_m_member_bank_accno
where membership_no = as_memno
and paid_dividen = '1'
;

return ls_bank_div;

exception when others then CALL spa_dberror('FP_GET_BANK_DIV');
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
